import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Product } from '../types';

const Home: React.FC = () => {
  const [recentProducts, setRecentProducts] = useState<Product[]>([]);
  const [selectedCategory, setSelectedCategory] = useState<string>('전체');

  const categories: string[] = ['전체', '페이스북', '인스타그램', '유튜브', '블로그', '트위터', '텔레그램', '기타'];

  // Mock data for popular products
  const popularProducts: Product[] = [
    { id: 1, name: '페이스북 팔로워 1000명', price: '50,000원', category: '페이스북', image: 'https://via.placeholder.com/200x150?text=Facebook' },
    { id: 2, name: '인스타그램 팔로워 500명', price: '30,000원', category: '인스타그램', image: 'https://via.placeholder.com/200x150?text=Instagram' },
    { id: 3, name: '유튜브 구독자 1000명', price: '100,000원', category: '유튜브', image: 'https://via.placeholder.com/200x150?text=YouTube' },
    { id: 4, name: '블로그 방문자 5000명', price: '80,000원', category: '블로그', image: 'https://via.placeholder.com/200x150?text=Blog' },
    { id: 5, name: '트위터 팔로워 300명', price: '20,000원', category: '트위터', image: 'https://via.placeholder.com/200x150?text=Twitter' },
    { id: 6, name: '텔레그램 멤버 200명', price: '15,000원', category: '텔레그램', image: 'https://via.placeholder.com/200x150?text=Telegram' },
    { id: 7, name: '페이스북 좋아요 2000개', price: '40,000원', category: '페이스북', image: 'https://via.placeholder.com/200x150?text=Facebook' },
    { id: 8, name: '인스타그램 좋아요 1000개', price: '25,000원', category: '인스타그램', image: 'https://via.placeholder.com/200x150?text=Instagram' },
    { id: 9, name: '유튜브 조회수 10000회', price: '60,000원', category: '유튜브', image: 'https://via.placeholder.com/200x150?text=YouTube' },
    { id: 10, name: '블로그 댓글 100개', price: '35,000원', category: '블로그', image: 'https://via.placeholder.com/200x150?text=Blog' },
    { id: 11, name: '트위터 리트윗 500개', price: '45,000원', category: '트위터', image: 'https://via.placeholder.com/200x150?text=Twitter' },
    { id: 12, name: '텔레그램 뷰 1000회', price: '30,000원', category: '텔레그램', image: 'https://via.placeholder.com/200x150?text=Telegram' },
  ];

  const filteredProducts: Product[] = selectedCategory === '전체' 
    ? popularProducts 
    : popularProducts.filter(product => product.category === selectedCategory);

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hero Section */}
      <div className="bg-gradient-to-r from-blue-600 to-blue-800 text-white py-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h1 className="text-4xl md:text-6xl font-bold mb-6">
            소셜미디어 마케팅의 새로운 기준
          </h1>
          <p className="text-xl md:text-2xl mb-8 text-blue-100">
            애드모어와 함께 당신의 소셜미디어를 성장시키세요
          </p>
          <Link
            to="/products"
            className="bg-white text-blue-600 px-8 py-3 rounded-lg text-lg font-semibold hover:bg-gray-100 transition duration-300"
          >
            상품 보기
          </Link>
        </div>
      </div>



      {/* Category Filter */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="flex flex-wrap gap-2 mb-8">
          {categories.map((category) => (
            <button
              key={category}
              onClick={() => setSelectedCategory(category)}
              className={`px-4 py-2 rounded-full text-sm font-medium transition duration-300 ${
                selectedCategory === category
                  ? 'bg-blue-600 text-white'
                  : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
              }`}
            >
              {category}
            </button>
          ))}
        </div>
      </div>

      {/* Popular Products Section */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <h2 className="text-3xl font-bold text-gray-900 mb-8">인기 상품</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          {filteredProducts.map((product) => (
            <div key={product.id} className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition duration-300">
              <img src={product.image} alt={product.name} className="w-full h-48 object-cover" />
              <div className="p-4">
                <h3 className="font-semibold text-gray-900 mb-2">{product.name}</h3>
                <p className="text-blue-600 font-bold">{product.price}</p>
                <button className="mt-3 w-full bg-blue-600 text-white py-2 rounded-md hover:bg-blue-700 transition duration-300">
                  구매하기
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* All Products Section */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <h2 className="text-3xl font-bold text-gray-900 mb-8">전체 상품</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          {filteredProducts.map((product) => (
            <div key={product.id} className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition duration-300">
              <img src={product.image} alt={product.name} className="w-full h-48 object-cover" />
              <div className="p-4">
                <h3 className="font-semibold text-gray-900 mb-2">{product.name}</h3>
                <p className="text-blue-600 font-bold">{product.price}</p>
                <button className="mt-3 w-full bg-blue-600 text-white py-2 rounded-md hover:bg-blue-700 transition duration-300">
                  구매하기
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Home;
